def solve(c: int, connections: list[list[int]], queries: list[list[int]]) -> list[int]:
    from collections import defaultdict, deque

    # Build the graph
    graph = defaultdict(list)
    for u, v in connections:
        graph[u].append(v)
        graph[v].append(u)

    # For each node, keep track of its current state (online or offline)
    online = [True] * (c + 1)  # 1-based indexing

    # For each node, keep track of the minimum online node in its connected component
    # We'll use BFS to find the minimum online node in the component
    def find_min_online_in_component(start):
        visited = set()
        queue = deque([start])
        visited.add(start)
        min_online = start
        while queue:
            node = queue.popleft()
            if online[node]:
                min_online = min(min_online, node)
            for neighbor in graph[node]:
                if neighbor not in visited:
                    visited.add(neighbor)
                    queue.append(neighbor)
        return min_online

    result = []

    for query in queries:
        if query[0] == 1:
            x = query[1]
            if online[x]:
                result.append(x)
            else:
                # Find the minimum online node in the same component
                min_online = find_min_online_in_component(x)
                if min_online == -1:
                    result.append(-1)
                else:
                    result.append(min_online)
        else:
            x = query[1]
            online[x] = False

    return result
